<!doctype html><html lang="zh-Hant"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>圖庫管理後台</title><link rel="stylesheet" href="style.css"></head><body><main id="app"></main><script>
let list=[],drag=null;const $=s=>document.querySelector(s),esc=s=>String(s||'').replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));async function api(action,data){let body=new FormData;if(data)Object.entries(data).forEach(([k,v])=>body.append(k,v));body.append('action',action);let r=await fetch('api.php',{method:'POST',body});let j=await r.json();if(!r.ok)throw new Error(j.error||'操作失敗');return j}async function check(){let s=await fetch('api.php?action=session').then(r=>r.json());s.loggedIn?load():login()}function login(){$('#app').innerHTML=`<section class="login"><p class="eyebrow">ADMIN LOGIN</p><h1 style="font-size:2.6rem">圖庫管理</h1><p class="hint">請輸入管理密碼。</p><form id="form"><input type="password" name="password" placeholder="管理密碼" required><button class="btn">登入後台</button><p id="msg" style="margin-top:12px;color:#b53c2c"></p></form></section>`;$('#form').onsubmit=async e=>{e.preventDefault();try{await api('login',{password:new FormData(e.target).get('password')});load()}catch(x){$('#msg').textContent=x.message}}}async function load(){let d=await fetch('api.php?action=list').then(r=>r.json());list=d.items;render()}function render(){$('#app').innerHTML=`<header class="hero"><div><p class="eyebrow">ADMIN DASHBOARD</p><h1>圖庫管理</h1><p class="hint">拖曳卡片即可變更主網站的顯示順序。</p></div><div class="actions"><a class="btn alt" href="index.html">查看主網站</a><button class="btn alt" id="logout">登出</button><button class="btn" id="add">＋ 新增圖片</button></div></header><section class="bar"><div><strong>主機端資料管理</strong><span>所有修改將立即儲存在主機並同步到 index.html。</span></div></section><section class="gallery" id="gallery"></section>`;$('#gallery').innerHTML=list.map((x,i)=>`<article class="card" draggable="true" data-id="${x.id}"><button class="photo" data-id="${x.id}"><img src="${x.image}" alt="${esc(x.title)}"></button><div class="copy"><span class="num">#${String(i+1).padStart(2,'0')}</span><h2>${esc(x.title)}</h2><p>${esc(x.description)}</p></div><div class="tools"><span class="handle">⠿ 拖曳排序</span><button data-edit="${x.id}">編輯</button><button class="del" data-del="${x.id}">刪除</button></div></article>`).join('');$('#add').onclick=()=>edit();$('#logout').onclick=async()=>{await api('logout');login()};document.querySelectorAll('[data-edit]').forEach(b=>b.onclick=()=>edit(list.find(x=>x.id===b.dataset.edit)));document.querySelectorAll('[data-del]').forEach(b=>b.onclick=async()=>{if(confirm('確定刪除？')){try{let r=await api('delete',{id:b.dataset.del});list=r.items;render()}catch(x){alert(x.message)}}});document.querySelectorAll('.card').forEach(c=>{c.ondragstart=()=>drag=c.dataset.id;c.ondragover=e=>e.preventDefault();c.ondrop=async e=>{e.preventDefault();let a=list.findIndex(x=>x.id===drag),b=list.findIndex(x=>x.id===c.dataset.id);if(a===b)return;let[m]=list.splice(a,1);list.splice(b,0,m);render();try{await api('reorder',{order:JSON.stringify(list.map(x=>x.id))})}catch(x){alert(x.message);load()}}})}function edit(x={id:crypto.randomUUID(),title:'',description:'',image:''}){let d=document.createElement('div');d.className='overlay';d.innerHTML=`<div class="editor"><p class="eyebrow">EDIT IMAGE</p><h2>${list.some(y=>y.id===x.id)?'修改圖片':'新增圖片'}</h2><label>圖片標題<input id="title" value="${esc(x.title)}"></label><label>文字說明<textarea id="description" rows="3">${esc(x.description)}</textarea></label><label>上傳新圖片（未選擇時保留原圖）<input id="image" type="file" accept="image/jpeg,image/png,image/webp,image/gif"></label>${x.image?`<img src="${x.image}" alt="預覽">`:''}<div class="foot"><button class="btn alt" id="cancel">取消</button><button class="btn" id="save">儲存</button></div></div>`;d.querySelector('#cancel').onclick=()=>d.remove();d.querySelector('#save').onclick=async()=>{let f=d.querySelector('#image').files[0],data={id:x.id,title:d.querySelector('#title').value.trim(),description:d.querySelector('#description').value.trim(),currentImage:x.image};if(f)data.image=f;try{let r=await api('save',data);list=r.items;d.remove();render()}catch(e){alert(e.message)}};document.body.append(d)}check();
</script></body></html>
